import React from 'react';

export function Section({
  id,
  title,
  level = 1,
  className,
  children
}: {
  id: string;
  title: string;
  level?: 1 | 2;
  className?: string;
  children: React.ReactNode;
}) {
  const Tag = level === 1 ? 'h2' : 'h3';
  const titleClass = level === 1
    ? 'text-2xl font-bold text-white mt-16 mb-6 first:mt-0'
    : 'text-xl font-semibold text-white/90 mt-10 mb-4';

  return (
    <section id={id} className={\`scroll-mt-24 \${className || ''}\`}>
      <Tag className={titleClass}>{title}</Tag>
      <div className="space-y-4 text-gray-400 leading-relaxed">
        {children}
      </div>
    </section>
  );
}

export function CodeBlock({ code }: { code: string }) {
  return (
    <pre className="bg-[#1a1a1d] border border-white/5 rounded-xl p-4 overflow-x-auto my-4">
      <code className="text-sm text-indigo-300" style={{ fontFamily: 'var(--font-mono)' }}>{code}</code>
    </pre>
  );
}
